macro.implementation:
do {
  osalSysLockFromISR();
  if ((i2sp)->sync_state == (state)) {
    osalThreadResumeI(&(i2sp)->thread, MSG_OK);
  }
  osalSysUnlockFromISR();
} while (false)

do {
  osalSysLockFromISR();
  osalThreadResumeI(&(i2sp)->thread, MSG_RESET);
  osalSysUnlockFromISR();
} while (false)

types.verbatim:
typedef struct hal_i2s_driver I2SDriver;
typedef struct hal_i2s_config I2SConfig;

/* Inclusion of LLD header.*/
#include "hal_i2s_lld.h"

objinit.implementation:
self->events = 0U;
self->errors = I2S_NO_ERROR;
#if I2S_USE_SYNCHRONIZATION == TRUE
self->thread     = NULL;
self->sync_state = HAL_DRV_STATE_STOP;
#endif

method.implementation:
msg_t msg;

osalDbgCheckClassI();
osalDbgCheck(self != NULL);
osalDbgAssert(self->state == HAL_DRV_STATE_READY, "not ready");
osalDbgAssert(self->config != NULL, "config missing");

self->events = 0U;
self->errors = I2S_NO_ERROR;
self->state  = HAL_DRV_STATE_ACTIVE;
msg = i2s_lld_start_exchange(self);
if (msg != HAL_RET_SUCCESS) {
  self->state = HAL_DRV_STATE_READY;
}

return msg;

msg_t msg;

osalSysLock();
msg = i2sStartExchangeI(self);
osalSysUnlock();

return msg;

osalDbgCheckClassI();
osalDbgCheck(self != NULL);
osalDbgAssert((self->state == HAL_DRV_STATE_READY)  ||
              (self->state == HAL_DRV_STATE_ACTIVE) ||
              (self->state == HAL_DRV_STATE_HALF)   ||
              (self->state == HAL_DRV_STATE_FULL)   ||
              (self->state == HAL_DRV_STATE_ERROR),
              "invalid state");

if (self->state != HAL_DRV_STATE_READY) {
  i2s_lld_stop_exchange(self);
  self->state = HAL_DRV_STATE_READY;
  _i2s_reset_i(self);
}

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert((self->state == HAL_DRV_STATE_READY)  ||
              (self->state == HAL_DRV_STATE_ACTIVE) ||
              (self->state == HAL_DRV_STATE_HALF)   ||
              (self->state == HAL_DRV_STATE_FULL)   ||
              (self->state == HAL_DRV_STATE_ERROR),
              "invalid state");
if (self->state != HAL_DRV_STATE_READY) {
  i2s_lld_stop_exchange(self);
  self->state = HAL_DRV_STATE_READY;
  _i2s_reset_s(self);
}
osalSysUnlock();

msg_t msg;

osalDbgCheck(self != NULL);
osalDbgCheckClassS();
osalDbgCheck((state == HAL_DRV_STATE_HALF) ||
             (state == HAL_DRV_STATE_FULL));
osalDbgAssert(self->state == HAL_DRV_STATE_ACTIVE, "invalid state");
osalDbgAssert(self->thread == NULL, "already waiting");

self->sync_state = state;
msg = osalThreadSuspendTimeoutS(&self->thread, timeout);
self->sync_state = HAL_DRV_STATE_STOP;

return msg;

msg_t msg;

osalDbgCheck(self != NULL);

osalSysLock();
msg = i2sSynchronizeStateS(self, state, timeout);
osalSysUnlock();

return msg;

i2seventflags_t flags;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
flags = self->events & mask;
self->events &= ~mask;
osalSysRestoreStatusX(sts);

return flags;

i2serror_t errors;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
errors = self->errors & mask;
self->errors &= ~mask;
osalSysRestoreStatusX(sts);

return errors;

if (config != NULL) {
  self->config = __i2s_setcfg_impl(self, config);
  if (self->config == NULL) {
    return HAL_RET_CONFIG_ERROR;
  }
}

if (self->config == NULL) {
  return HAL_RET_CONFIG_ERROR;
}

self->events = 0U;
self->errors = I2S_NO_ERROR;

return i2s_lld_start(self);
